-- ----------------------------
-- Table structure for ai_training_sample
-- ----------------------------
DROP TABLE IF EXISTS `ai_training_sample`;
CREATE TABLE `ai_training_sample`  (
                                       `id` bigint UNSIGNED NOT NULL COMMENT 'pk',
                                       `file_id` bigint UNSIGNED NOT NULL COMMENT 'file id',
                                       `image_region_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'cropped image path',
                                       `coordinate` json NULL COMMENT 'bounding box [x1,y1,x2,y2]',
                                       `field_key` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'field key',
                                       `ocr_value` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'original value',
                                       `corrected_value` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'corrected value',
                                       `is_trained` tinyint NULL DEFAULT 0 COMMENT '0 not trained, 1 trained',
                                       `create_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3),
                                       PRIMARY KEY (`id`) USING BTREE,
                                       INDEX `idx_field`(`field_key` ASC) USING BTREE,
                                       INDEX `idx_trained`(`is_trained` ASC) USING BTREE,
                                       INDEX `idx_ai_file`(`file_id` ASC) USING BTREE,
                                       CONSTRAINT `fk_training_file` FOREIGN KEY (`file_id`) REFERENCES `document_file` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
                                       CONSTRAINT `ai_training_sample_chk_1` CHECK (`is_trained` in (0,1)),
                                       CONSTRAINT `ai_training_sample_chk_2` CHECK ((`coordinate` is null) or json_valid(`coordinate`))
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'AI training samples' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of ai_training_sample
-- ----------------------------

-- ----------------------------
-- Table structure for audit_record
-- ----------------------------
DROP TABLE IF EXISTS `audit_record`;
CREATE TABLE `audit_record`  (
                                 `id` bigint UNSIGNED NOT NULL COMMENT 'pk',
                                 `file_id` bigint UNSIGNED NOT NULL COMMENT 'file id',
                                 `auditor_id` bigint UNSIGNED NOT NULL COMMENT 'auditor user id',
                                 `action_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'APPROVE, REJECT, MODIFY',
                                 `comment` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
                                 `create_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3),
                                 `extract_main_id` bigint NULL DEFAULT NULL COMMENT '提取主表ID',
                                 `audit_status` int NULL DEFAULT NULL COMMENT '审核状态',
                                 `audit_comment` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '审核意见',
                                 PRIMARY KEY (`id`) USING BTREE,
                                 INDEX `idx_file`(`file_id` ASC) USING BTREE,
                                 INDEX `idx_auditor`(`auditor_id` ASC) USING BTREE,
                                 CONSTRAINT `fk_audit_file` FOREIGN KEY (`file_id`) REFERENCES `document_file` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
                                 CONSTRAINT `fk_audit_user` FOREIGN KEY (`auditor_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Audit records' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of audit_record
-- ----------------------------

-- ----------------------------
-- Table structure for document_extract_detail
-- ----------------------------
DROP TABLE IF EXISTS `document_extract_detail`;
CREATE TABLE `document_extract_detail`  (
                                            `id` bigint UNSIGNED NOT NULL COMMENT 'pk',
                                            `file_id` bigint UNSIGNED NOT NULL COMMENT 'file id',
                                            `main_id` bigint UNSIGNED NOT NULL COMMENT 'extract main id',
                                            `row_index` int NULL DEFAULT NULL COMMENT 'row index (0-based)',
                                            `row_data_json` json NOT NULL COMMENT 'structured row data (complete row)',
                                            `field_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'field name (for single field extraction)',
                                            `field_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'field value (for single field extraction)',
                                            `row_confidence` decimal(5, 4) NULL DEFAULT NULL COMMENT 'row confidence 0-1',
                                            `is_verified` tinyint NULL DEFAULT 0 COMMENT '0-not verified, 1-verified by human',
                                            `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
                                            `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
                                            PRIMARY KEY (`id`) USING BTREE,
                                            INDEX `idx_file`(`file_id` ASC) USING BTREE,
                                            INDEX `idx_main`(`main_id` ASC) USING BTREE,
                                            INDEX `idx_row_index`(`row_index` ASC) USING BTREE,
                                            INDEX `idx_verified`(`is_verified` ASC) USING BTREE,
                                            CONSTRAINT `fk_detail_file` FOREIGN KEY (`file_id`) REFERENCES `document_file` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
                                            CONSTRAINT `fk_detail_main` FOREIGN KEY (`main_id`) REFERENCES `document_extract_main` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
                                            CONSTRAINT `document_extract_detail_chk_1` CHECK (`is_verified` in (0,1)),
                                            CONSTRAINT `document_extract_detail_chk_2` CHECK (json_valid(`row_data_json`))
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Extracted table detail' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of document_extract_detail
-- ----------------------------

-- ----------------------------
-- Table structure for document_extract_main
-- ----------------------------
DROP TABLE IF EXISTS `document_extract_main`;
CREATE TABLE `document_extract_main`  (
                                          `id` bigint UNSIGNED NOT NULL COMMENT 'pk',
                                          `file_id` bigint UNSIGNED NOT NULL COMMENT 'file id',
                                          `template_id` bigint UNSIGNED NULL DEFAULT NULL COMMENT 'template id',
                                          `owner_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'owner id (student_id/employee_id)',
                                          `owner_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'owner name',
                                          `kv_data_json` json NULL COMMENT 'kv data (key-value pairs)',
                                          `extract_result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'complete extraction result JSON',
                                          `confidence` decimal(5, 4) NULL DEFAULT NULL COMMENT 'extraction confidence 0-1',
                                          `status` tinyint NULL DEFAULT 0 COMMENT '0-pending review, 1-reviewed, 2-confirmed',
                                          `document_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'document type (transcript, certificate, leave_application, etc.)',
                                          `document_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'document access URL (MinIO presigned URL)',
                                          `raw_text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'OCR raw text content',
                                          `basic_info_json` json NULL COMMENT 'basic info JSON (name, student_id, school, etc.)',
                                          `academic_info_json` json NULL COMMENT 'academic info JSON (degree, enroll_date, etc.)',
                                          `certificate_info_json` json NULL COMMENT 'certificate info JSON (cert_id, issue_date, etc.)',
                                          `financial_info_json` json NULL COMMENT 'financial info JSON (bank_account, loan_amount, etc.)',
                                          `leave_info_json` json NULL COMMENT 'leave info JSON (reason, days, etc.)',
                                          `summary` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'document summary',
                                          `tables_json` json NULL COMMENT 'table data JSON (courses, scores, etc.)',
                                          `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
                                          `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
                                          PRIMARY KEY (`id`) USING BTREE,
                                          UNIQUE INDEX `uk_file_main`(`file_id` ASC) USING BTREE,
                                          INDEX `idx_owner_id`(`owner_id` ASC) USING BTREE,
                                          INDEX `idx_owner_name`(`owner_name` ASC) USING BTREE,
                                          INDEX `idx_status`(`status` ASC) USING BTREE,
                                          INDEX `idx_document_type`(`document_type` ASC) USING BTREE,
                                          INDEX `fk_extract_main_template`(`template_id` ASC) USING BTREE,
                                          CONSTRAINT `fk_extract_main_file` FOREIGN KEY (`file_id`) REFERENCES `document_file` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
                                          CONSTRAINT `fk_extract_main_template` FOREIGN KEY (`template_id`) REFERENCES `sys_doc_template` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT,
                                          CONSTRAINT `document_extract_main_chk_1` CHECK ((`kv_data_json` is null) or json_valid(`kv_data_json`)),
                                          CONSTRAINT `document_extract_main_chk_2` CHECK ((`basic_info_json` is null) or json_valid(`basic_info_json`)),
                                          CONSTRAINT `document_extract_main_chk_3` CHECK ((`academic_info_json` is null) or json_valid(`academic_info_json`)),
                                          CONSTRAINT `document_extract_main_chk_4` CHECK ((`certificate_info_json` is null) or json_valid(`certificate_info_json`)),
                                          CONSTRAINT `document_extract_main_chk_5` CHECK ((`financial_info_json` is null) or json_valid(`financial_info_json`)),
                                          CONSTRAINT `document_extract_main_chk_6` CHECK ((`leave_info_json` is null) or json_valid(`leave_info_json`)),
                                          CONSTRAINT `document_extract_main_chk_7` CHECK ((`tables_json` is null) or json_valid(`tables_json`)),
                                          CONSTRAINT `document_extract_main_chk_8` CHECK (`status` in (0,1,2))
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Extracted KV data' ROW_FORMAT = Dynamic;

