-- ----------------------------
-- Table structure for document_file
-- ----------------------------
DROP TABLE IF EXISTS `document_file`;
CREATE TABLE `document_file`  (
                                  `id` bigint UNSIGNED NOT NULL COMMENT 'pk',
                                  `user_id` bigint UNSIGNED NOT NULL COMMENT 'uploader id',
                                  `template_id` bigint UNSIGNED NULL DEFAULT NULL COMMENT 'template id',
                                  `batch_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'batch no',
                                  `file_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'business number',
                                  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
                                  `file_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'img/pdf',
                                  `file_size` bigint NULL DEFAULT NULL,
                                  `minio_bucket` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
                                  `minio_object` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
                                  `thumbnail_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
                                  `process_status` tinyint NULL DEFAULT 0 COMMENT '0 pending 1 queued 2 processing 3 manual 4 archived 5 failed',
                                  `process_mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'STANDARD' COMMENT 'STANDARD / LLM_FALLBACK',
                                  `retry_count` int NULL DEFAULT 0 COMMENT 'retry times',
                                  `fail_reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
                                  `deleted` tinyint NULL DEFAULT 0,
                                  `version` int NULL DEFAULT 0,
                                  `create_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3),
                                  `update_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
                                  PRIMARY KEY (`id`) USING BTREE,
                                  UNIQUE INDEX `file_no`(`file_no` ASC) USING BTREE,
                                  INDEX `idx_user`(`user_id` ASC) USING BTREE,
                                  INDEX `idx_status`(`process_status` ASC) USING BTREE,
                                  INDEX `idx_batch`(`batch_no` ASC) USING BTREE,
                                  INDEX `idx_template`(`template_id` ASC) USING BTREE,
                                  INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
                                  CONSTRAINT `fk_document_template` FOREIGN KEY (`template_id`) REFERENCES `sys_doc_template` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT,
                                  CONSTRAINT `fk_document_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
                                  CONSTRAINT `document_file_chk_1` CHECK (`process_status` in (0,1,2,3,4,5)),
                                  CONSTRAINT `document_file_chk_2` CHECK (`deleted` in (0,1))
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Document files' ROW_FORMAT = Dynamic;

