-- ----------------------------
-- Table structure for document_ocr_raw
-- ----------------------------
DROP TABLE IF EXISTS `document_ocr_raw`;
CREATE TABLE `document_ocr_raw`  (
                                     `id` bigint UNSIGNED NOT NULL COMMENT 'pk',
                                     `file_id` bigint UNSIGNED NOT NULL COMMENT 'file id',
                                     `full_text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'plain text result',
                                     `raw_data_json` json NULL COMMENT 'ocr result with coordinates',
                                     `text_count` int GENERATED ALWAYS AS (json_length(`raw_data_json`)) VIRTUAL COMMENT 'block count' NULL,
                                     `avg_confidence` decimal(5, 4) NULL DEFAULT NULL COMMENT 'average confidence',
                                     `is_llm_used` tinyint NULL DEFAULT 0 COMMENT '1 if LLM used',
                                     `token_usage` int NULL DEFAULT 0 COMMENT 'LLM token usage',
                                     `create_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3),
                                     PRIMARY KEY (`id`) USING BTREE,
                                     UNIQUE INDEX `uk_file`(`file_id` ASC) USING BTREE,
                                     INDEX `idx_file`(`file_id` ASC) USING BTREE,
                                     INDEX `idx_avg_confidence`(`avg_confidence` ASC) USING BTREE,
                                     INDEX `idx_text_len`(`text_count` ASC) USING BTREE,
                                     CONSTRAINT `fk_ocr_file` FOREIGN KEY (`file_id`) REFERENCES `document_file` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
                                     CONSTRAINT `document_ocr_raw_chk_1` CHECK (`is_llm_used` in (0,1)),
                                     CONSTRAINT `document_ocr_raw_chk_2` CHECK ((`raw_data_json` is null) or json_valid(`raw_data_json`))
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'OCR raw result' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of document_ocr_raw
-- ----------------------------

-- ----------------------------
-- Table structure for sys_doc_template
-- ----------------------------
DROP TABLE IF EXISTS `sys_doc_template`;
CREATE TABLE `sys_doc_template`  (
                                     `id` bigint UNSIGNED NOT NULL COMMENT 'template id (snowflake)',
                                     `template_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'template name',
                                     `template_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'code e.g. TRANSCRIPT',
                                     `target_kv_config` json NULL COMMENT 'KV extraction rules',
                                     `target_table_config` json NULL COMMENT 'table extraction rules',
                                     `rule_config` json NULL COMMENT 'validation rules',
                                     `status` tinyint NULL DEFAULT 1 COMMENT '1 enabled, 0 disabled',
                                     `create_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3),
                                     `update_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
                                     PRIMARY KEY (`id`) USING BTREE,
                                     UNIQUE INDEX `template_code`(`template_code` ASC) USING BTREE,
                                     CONSTRAINT `sys_doc_template_chk_1` CHECK (`status` in (0,1)),
                                     CONSTRAINT `sys_doc_template_chk_2` CHECK ((`target_kv_config` is null) or json_valid(`target_kv_config`)),
                                     CONSTRAINT `sys_doc_template_chk_3` CHECK ((`target_table_config` is null) or json_valid(`target_table_config`)),
                                     CONSTRAINT `sys_doc_template_chk_4` CHECK ((`rule_config` is null) or json_valid(`rule_config`))
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Document template config' ROW_FORMAT = Dynamic;

