-- ----------------------------
-- Table structure for sys_role
-- ----------------------------
DROP TABLE IF EXISTS `sys_role`;
CREATE TABLE `sys_role`  (
                             `id` bigint UNSIGNED NOT NULL COMMENT 'role id (snowflake)',
                             `role_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'role name',
                             `role_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'role key e.g. ROLE_ADMIN',
                             `status` tinyint NULL DEFAULT 1,
                             `deleted` tinyint NULL DEFAULT 0,
                             `create_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3),
                             PRIMARY KEY (`id`) USING BTREE,
                             UNIQUE INDEX `uk_role_key`(`role_key` ASC) USING BTREE,
                             UNIQUE INDEX `uk_role_name`(`role_name` ASC) USING BTREE,
                             CONSTRAINT `sys_role_chk_1` CHECK (`status` in (0,1)),
                             CONSTRAINT `sys_role_chk_2` CHECK (`deleted` in (0,1))
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Roles' ROW_FORMAT = Dynamic;

