-- ----------------------------
-- Table structure for sys_task_log
-- ----------------------------
DROP TABLE IF EXISTS `sys_task_log`;
CREATE TABLE `sys_task_log`  (
                                 `id` bigint UNSIGNED NOT NULL COMMENT 'pk',
                                 `trace_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'trace id',
                                 `file_id` bigint UNSIGNED NULL DEFAULT NULL COMMENT 'file id',
                                 `stage` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'UPLOAD, OCR, NLP, RULE',
                                 `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'SUCCESS, FAIL',
                                 `cost_ms` bigint NULL DEFAULT NULL COMMENT 'cost in ms',
                                 `error_msg` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
                                 `create_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3),
                                 PRIMARY KEY (`id`) USING BTREE,
                                 INDEX `idx_file`(`file_id` ASC) USING BTREE,
                                 INDEX `idx_trace`(`trace_id` ASC) USING BTREE,
                                 CONSTRAINT `fk_tasklog_file` FOREIGN KEY (`file_id`) REFERENCES `document_file` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT,
                                 CONSTRAINT `sys_task_log_chk_1` CHECK (`stage` in (_utf8mb4'UPLOAD',_utf8mb4'OCR',_utf8mb4'NLP',_utf8mb4'RULE')),
                                 CONSTRAINT `sys_task_log_chk_2` CHECK (`status` in (_utf8mb4'SUCCESS',_utf8mb4'FAIL'))
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Task log' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_task_log
-- ----------------------------

-- ----------------------------
-- Table structure for sys_user
-- ----------------------------
DROP TABLE IF EXISTS `sys_user`;
CREATE TABLE `sys_user`  (
                             `id` bigint UNSIGNED NOT NULL COMMENT 'user id (snowflake)',
                             `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'login name',
                             `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'BCrypt password',
                             `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
                             `email` varchar(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
                             `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
                             `avatar` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
                             `token_version` int NULL DEFAULT 1 COMMENT 'token version',
                             `status` tinyint NULL DEFAULT 1 COMMENT '1 enabled 0 disabled',
                             `deleted` tinyint NULL DEFAULT 0 COMMENT 'logical delete',
                             `version` int NULL DEFAULT 0 COMMENT 'optimistic lock',
                             `create_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3),
                             `update_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
                             PRIMARY KEY (`id`) USING BTREE,
                             UNIQUE INDEX `uk_username`(`username` ASC) USING BTREE,
                             INDEX `idx_phone`(`phone` ASC) USING BTREE,
                             INDEX `idx_email`(`email` ASC) USING BTREE,
                             CONSTRAINT `sys_user_chk_1` CHECK (`status` in (0,1)),
                             CONSTRAINT `sys_user_chk_2` CHECK (`deleted` in (0,1))
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Users' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_user
-- ----------------------------
