-- ----------------------------
-- Table structure for sys_user_role
-- ----------------------------
DROP TABLE IF EXISTS `sys_user_role`;
CREATE TABLE `sys_user_role`  (
                                  `id` bigint UNSIGNED NOT NULL COMMENT 'pk (snowflake)',
                                  `user_id` bigint UNSIGNED NOT NULL COMMENT 'user id',
                                  `role_id` bigint UNSIGNED NOT NULL COMMENT 'role id',
                                  `create_time` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3),
                                  PRIMARY KEY (`id`) USING BTREE,
                                  UNIQUE INDEX `uk_user_role`(`user_id` ASC, `role_id` ASC) USING BTREE,
                                  INDEX `idx_user_role`(`user_id` ASC, `role_id` ASC) USING BTREE,
                                  INDEX `idx_role_user`(`role_id` ASC, `user_id` ASC) USING BTREE,
                                  CONSTRAINT `fk_user_role_role` FOREIGN KEY (`role_id`) REFERENCES `sys_role` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
                                  CONSTRAINT `fk_user_role_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'User-role mapping' ROW_FORMAT = Dynamic;

